        int sum = 0;
        String s = String.valueOf(n);
        for (char c : s.toCharArray()) {
            sum += c - '0';
        }
        return sum;
    }

    /**
     * Calculates the number of different valid arrays.
     * @param digitSum An array where digitSum[i] is the required digit sum for arr[i].
     * @return The count modulo 10^9 + 7.
     */
