        // Since the maximum digit sum is 50, we pre-calculate up to 50.
        for (int s = 0; s <= 50; s++) {
            List<Integer> nums = solution.getNumbersWithDigitSum(s);
            validNumbersBySum.put(s, nums);
        }

        // Step 2: Dynamic Programming
        // dp[i][j] = number of valid prefixes arr[0...i] such that arr[i] = j.
        // Since the range of j is [0, 5000], a direct DP table is too large.
        // We use a map-based DP or focus on the transition.

        // dp[i] will store a map: {value_of_arr[i] -> count_of_ways}
        // We only need the results from the previous step (i-1) to calculate the current step (i).

        // dp_prev: Map<Integer, Long> where key is arr[i-1], value is count
        // Initialize for i = 0 (the first element)
        Map<Integer, Long> dp_prev = new HashMap<>();
        int s0 = (int) digitSum[0];
        List<Integer> nums0 = validNumbersBySum.getOrDefault(s0, new ArrayList<>());

        for (int num : nums0) {
            dp_prev.put(num, (dp_prev.getOrDefault(num, 0L) + 1) % MOD);
        }

        // Iterate from i = 1 to n-1
        for (int i = 1; i < n; i++) {
            int si = (int) digitSum[i];
            List<Integer> nums_i = validNumbersBySum.getOrDefault(si, new ArrayList<>());

            Map<Integer, Long> dp_current = new HashMap<>();

            // Calculate dp_current based on dp_prev
            for (int current_num : nums_i) {
                long count = 0;

                // Sum up counts from all previous numbers (prev_num) such that prev_num <= current_num
                for (Map.Entry<Integer, Long> entry : dp_prev.entrySet()) {
                    int prev_num = entry.getKey();
                    long prev_count = entry.getValue();

                    if (prev_num <= current_num) {
                        count = (count + prev_count) % MOD;
                    }
                }

                if (count > 0) {
                    dp_current.put(current_num, count);
                }
            }

            dp_prev = dp_current;

            // If dp_prev becomes empty, no valid continuation exists.
            if (dp_prev.isEmpty()) {
                return 0;
            }
        }

        // Step 3: Sum up all counts in the final DP map
        long totalCount = 0;
        for (long count : dp_prev.values()) {
            totalCount = (totalCount + count) % MOD;
        }

        return totalCount;
    }
