import java.util.List;
import java.util.Map;

class Solution {
    private static final int MOD = 1_000_000_007;
    private static final int MAX_VAL = 5000;

    /**
     * Precomputes all numbers <= 5000 and their digit sums.
     * Returns a map where key is digit sum, and value is a sorted list of numbers having that digit sum.
     */
    private Map<Integer, List<Integer>> precomputeNumbers() {
        Map<Integer, List<Integer>> map = new HashMap<>();
        for (int i = 0; i <= MAX_VAL; i++) {
            int sum = getDigitSum(i);
            map.putIfAbsent(sum, new ArrayList<>());
            map.get(sum).add(i);
        }
        // Sort the lists for easier DP transition
        for (List<Integer> list : map.values()) {
            list.sort(null);
        }
        return map;
    }

    private int getDigitSum(int n) {
        int sum = 0;
        while (n > 0) {
            sum += n % 10;
            n /= 10;
        }
        return sum;
    }

    public static long solve(long[] digitSum) {
        Solution solution = new Solution();

        // Since we are constrained by MAX_VAL = 5000, we can precompute all valid numbers.
        Map<Integer, List<Integer>> numberMap = solution.precomputeNumbers();

        // DP state: dp[i][j] is the number of valid prefixes of length i+1 
        // such that the (i+1)-th element is the j-th number in the list corresponding to digitSum[i].
        // This seems too complex due to the state space for j.

        // A better DP approach:
        // dp[i][prev_val] = number of valid arrays of length i+1 where the last element is prev_val.
        // Since prev_val can be up to 5000, this is feasible.

        int n = digitSum.length;

        // Map: digit_sum -> list of numbers
        // We need to access this from inside the method, so we use the precomputed map.

        // dp[i][k]: Number of ways to form a valid prefix of length i+1 
        // such that the (i+1)-th element is the k-th smallest number with digit sum digitSum[i].

        // Let's map the numbers for easier indexing.
        // Valid numbers for each required digit sum:
        List<List<Integer>> validNumbersList = new ArrayList<>(n);
        for(int i = 0; i < n; i++) {
            int targetSum = (int)digitSum[i];
            List<Integer> nums = numberMap.getOrDefault(targetSum, new ArrayList<>());
            // If any required sum has no numbers in [0, 5000], the answer is 0.
            if (nums.isEmpty() && (targetSum != 0 || MAX_VAL < 0)) { // Only check if 0 is possible, 0 is always possible if sum is 0
                 if (targetSum >= 0 && targetSum <= 50) {
                    // Check if 0 is the only possible number for sum 0, and if 0 is in the map.
                    // Since we iterate 0 to 5000, if targetSum is in [0, 50] and no numbers are found, it's 0.
                    if (targetSum == 0) { // 0 has digit sum 0. It should be in the map.
                         // If it's truly empty, it means the precomputation missed 0, which is unlikely.
                    } else {
                        return 0;
                    }
                 }
            }
            validNumbersList.add(nums);
        }

        // Check for impossible sums based on constraints
        for(int i = 0; i < n; i++) {
            int targetSum = (int)digitSum[i];
            if (!numberMap.containsKey(targetSum) || numberMap.get(targetSum).isEmpty()) {
                return 0;
            }
        }

        // dp[i] will store a map: {index_of_number_in_list_i -> count}
        // where index_of_number_in_list_i refers to the position in validNumbersList.get(i).

        // dp[i] maps the index j of the number in validNumbersList.get(i) 
        // to the number of ways to form a valid prefix of length i+1 ending with validNumbersList.get(i).get(j).

        // Base case: i = 0
        Map<Integer, Long> dp_curr = new HashMap<>();
        List<Integer> nums0 = validNumbersList.get(0);
        for (int j = 0; j < nums0.size(); j++) {
            dp_curr.put(j, 1L);
        }

        // Transition: i = 1 to n-1
        for (int i = 1; i < n; i++) {
            Map<Integer, Long> dp_next = new HashMap<>();
            List<Integer> nums_prev = validNumbersList.get(i - 1);
            List<Integer> nums_curr = validNumbersList.get(i);

            for (int j_curr = 0; j_curr < nums_curr.size(); j_curr++) {
                int current_val = nums_curr.get(j_curr);
                long total_ways = 0;

                // Sum up ways from previous valid states
                for (Map.Entry<Integer, Long> entry : dp_curr.entrySet()) {
                    int j_prev = entry.getKey();
                    long ways_prev = entry.getValue();
                    int previous_val = nums_prev.get(j_prev);

                    // Non-decreasing condition: previous_val <= current_val
                    if (previous_val <= current_val) {
                        total_ways = (total_ways + ways_prev) % MOD;
                    }
                }

                if (total_ways > 0) {
                    dp_next.put(j_curr, total_ways);
                }
            }
            dp_curr = dp_next;
        }

        // Final result: sum of all counts in the last DP map
        long result = 0;
        for (long count : dp_curr.values()) {
            result = (result + count) % MOD;
        }

        return result;
    }
